module.render:
const esc = (s) => String(s).replace(/&/g,'&amp;').replace(/</g,'&lt;').replace(/>/g,'&gt;');
const number = (args.number || '').trim();
const body = (content || '').trim();
const align = String(args.align || 'center').toLowerCase();
const side = String(args.numberside || 'right').toLowerCase();
const size = String(args.size || 'normal').toLowerCase();
const scale = size === 'small' ? '0.85em' : size === 'large' ? '1.3em' : '1em';
const tagColor = args.color || 'var(--app-text-muted, #888)';
const tag = number ? `<span class="mdp-eq-tag">(${esc(number)})</span>` : '';
const bodyDiv = `<div class="mdp-eq-body" style="text-align:${align};">\n\n\\[ ${body} \\]\n\n</div>`;
const inner = side === 'left' ? tag + bodyDiv : bodyDiv + tag;
return `\n\n<div class="mdp-mod-equation" style="font-size:${scale}; --eq-tagcolor:${tagColor};">${inner}</div>\n\n`;
